WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/48.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/48.0/apex.js")} 

sforce.connection.sessionId = '{!$Api.Session_ID}'; 

var selected = {!GETRECORDIDS($ObjectType.Aplicacion__c)}; 

if(selected.length>0){

var result = sforce.apex.execute("ws_Desaplicar","desaplicarFromAplicaciones", {idsAplicaciones:selected}); 

var json = JSON.parse(result[0]); 

console.log(json); 

if(json.isSuccess == false){ 
alert(json.errors.join('\n')); 
}else{ 
alert('Desaplicación Realizada'); 
location.reload(); 
}

}else{
alert('Debe seleccionar al menos una Aplicación.'); 
}
